// // This module implements an 8-bit register with asynchronous reset.
module register_8bit(clk, rst, d, q);

    input  clk, rst;
    input  [7:0] d;
    output reg [7:0] q;

    always @(posedge clk) begin
        if (rst)
            q <= 8'b00000000;
        else
            q <= d;
    end

endmodule
